package com.mengwei.localgrowth.evidence;

import com.mengwei.localgrowth.audit.AuditService;
import com.mengwei.localgrowth.identity.AuthService.Identity;
import com.mengwei.localgrowth.shared.ApiExceptionHandler.ApiException;
import java.math.BigDecimal; import java.math.RoundingMode; import java.time.OffsetDateTime; import java.util.*;
import org.springframework.http.HttpStatus; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Service;

@Service public class EvidenceService {
  private static final Set<String> SOURCES=Set.of("MOCK","API_MODEL","MANUAL_APP_OBSERVATION","SEARCH_API");
  private static final Set<String> CATEGORIES=Set.of("RECOMMENDATION","PRICE","PAIN_POINT","COMPARISON","LOCATION");
  private final JdbcTemplate jdbc; private final AuditService audit;
  public EvidenceService(JdbcTemplate jdbc,AuditService audit){this.jdbc=jdbc;this.audit=audit;}

  public Map<String,Object> importObservation(Identity i, ObservationInput in){
    if(!SOURCES.contains(in.sourceType())) throw bad("SOURCE_TYPE_INVALID","未知结果来源");
    var merchant=one("select id from merchants where id=? and tenant_id=? and deleted=false",in.merchantId(),i.tenantId());
    var question=one("select id from prompt_cases where id=? and merchant_id=? and tenant_id=? and deleted=false",in.questionId(),in.merchantId(),i.tenantId());
    var brand=one("select name,aliases from brands where merchant_id=? and tenant_id=? and deleted=false order by created_at limit 1",in.merchantId(),i.tenantId());
    var competitors=jdbc.queryForList("select name,aliases from competitors where merchant_id=? and tenant_id=? and deleted=false",in.merchantId(),i.tenantId());
    List<String> brandTerms=terms((String)brand.get("name"),(String)brand.get("aliases"));int first=first(in.rawAnswer(),brandTerms);int count=count(in.rawAnswer(),brandTerms);Map<String,Integer> comp=new LinkedHashMap<>();for(var c:competitors){int n=count(in.rawAnswer(),terms((String)c.get("name"),(String)c.get("aliases")));if(n>0)comp.put((String)c.get("name"),n);}
    if(in.screenshotAssetId()!=null)one("select id from assets where id=? and tenant_id=?",in.screenshotAssetId(),i.tenantId());
    UUID id=UUID.randomUUID();OffsetDateTime now=OffsetDateTime.now();jdbc.update("insert into evidence_observations (id,tenant_id,merchant_id,prompt_case_id,platform,model_name,source_type,search_enabled,raw_answer,captured_at,citation_links,screenshot_asset_id,operator_notes,brand_mention_count,brand_first_position,competitor_summary,created_at,updated_at,created_by,updated_by,version,is_demo) values (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",id,i.tenantId(),in.merchantId(),in.questionId(),in.platform(),in.modelName(),in.sourceType(),in.searchEnabled(),in.rawAnswer(),in.capturedAt(),safe(in.citationLinks()),in.screenshotAssetId(),safe(in.operatorNotes()),count,first<0?null:first,encodeCounts(comp),now,now,i.userId(),i.userId(),0L,false);
    audit.log(i.tenantId(),i.userId(),"EVIDENCE_IMPORTED","EvidenceObservation",id,"导入 "+in.sourceType()+" 真实回答，品牌命中 "+count+" 次");return observation(i,id);
  }
  public List<Map<String,Object>> observations(Identity i,UUID merchantId){assertMerchant(i,merchantId);return jdbc.queryForList("select o.id,o.prompt_case_id,p.question,p.category,p.city,p.district,p.intent_level,o.platform,o.model_name,o.source_type,o.search_enabled,o.raw_answer,o.captured_at,o.citation_links,o.screenshot_asset_id,o.operator_notes,o.brand_mention_count,o.brand_first_position,o.competitor_summary,o.is_demo,a.original_filename as screenshot_filename from evidence_observations o join prompt_cases p on p.id=o.prompt_case_id left join assets a on a.id=o.screenshot_asset_id and a.tenant_id=o.tenant_id where o.tenant_id=? and o.merchant_id=? order by o.captured_at desc",i.tenantId(),merchantId);}
  public Map<String,Object> formalReport(Identity i,UUID merchantId){
    var merchant=one("select name,city,district,industry from merchants where id=? and tenant_id=? and deleted=false",merchantId,i.tenantId());var brand=one("select name,website,services,claims from brands where merchant_id=? and tenant_id=? and deleted=false order by created_at limit 1",merchantId,i.tenantId());
    var questions=jdbc.queryForList("select id,question,category,city,district,intent_level from prompt_cases where tenant_id=? and merchant_id=? and enabled=true and deleted=false order by sort_order,created_at",i.tenantId(),merchantId);if(questions.size()<20)throw bad("INSUFFICIENT_QUESTIONS","正式诊断需要至少20个启用问题；当前为 "+questions.size()+" 个");
    var all=jdbc.queryForList("select o.*,p.question,p.category,p.city,p.district,p.intent_level from evidence_observations o join prompt_cases p on p.id=o.prompt_case_id where o.tenant_id=? and o.merchant_id=? and o.source_type <> 'MOCK' and o.is_demo=false order by o.captured_at",i.tenantId(),merchantId);if(all.isEmpty())throw bad("NO_REAL_EVIDENCE","请先导入非演示的 API_MODEL、MANUAL_APP_OBSERVATION 或 SEARCH_API 真实回答");
    UUID run=UUID.randomUUID();OffsetDateTime now=OffsetDateTime.now();jdbc.update("insert into diagnostic_runs values (?,?,?,?,?,?,?,?,?,?,?)",run,i.tenantId(),merchantId,"COMPLETED","GEO_SCORE_V2","正式评分仅使用非 Mock 的导入证据；按来源独立计算。",now,now,i.userId(),i.userId(),0L);
    Map<String,ScoreGroup> groups=new LinkedHashMap<>();for(String source:List.of("MANUAL_APP_OBSERVATION","API_MODEL","SEARCH_API")){List<Map<String,Object>> records=all.stream().filter(x->source.equals(x.get("source_type"))).toList();if(!records.isEmpty())groups.put(source,score(source,records,questions));}
    boolean formal=groups.values().stream().anyMatch(ScoreGroup::publishable);String markdown=markdown(merchant,brand,questions,all,groups,formal);String snapshot=snapshot(questions,all,groups,formal);double primary=groups.values().stream().filter(ScoreGroup::publishable).mapToDouble(ScoreGroup::total).findFirst().orElse(0);UUID report=UUID.randomUUID();jdbc.update("insert into diagnostic_reports values (?,?,?,?,?,?,?,?,?,?,?)",report,i.tenantId(),run,primary,markdown,snapshot,now,now,i.userId(),i.userId(),0L);audit.log(i.tenantId(),i.userId(),"FORMAL_REPORT_GENERATED","DiagnosticReport",report,"生成 GEO_SCORE_V2 报告，真实证据 "+all.size()+" 条");
    return Map.of("runId",run,"reportId",report,"formalScorePublished",formal,"scoreGroups",groups.values().stream().map(ScoreGroup::asMap).toList(),"evidenceCount",all.size(),"questionCount",questions.size(),"reportMarkdown",markdown,"evidence",evidenceView(all));
  }
  private ScoreGroup score(String source,List<Map<String,Object>> rows,List<Map<String,Object>> questions){int n=rows.size(), q=questions.size();int covered=(int)rows.stream().map(x->x.get("prompt_case_id")).distinct().count();int hits=(int)rows.stream().filter(x->((Number)x.get("brand_mention_count")).intValue()>0).count();double coverage=100d*covered/q, appearance=100d*hits/n;double position=rows.stream().filter(x->x.get("brand_first_position")!=null).mapToDouble(x->{int p=((Number)x.get("brand_first_position")).intValue();int len=((String)x.get("raw_answer")).length();return clamp(100d-100d*p/Math.max(1,len));}).average().orElse(0);double evidence=rows.stream().mapToDouble(x->(!blank((String)x.get("citation_links"))?60:0)+(x.get("screenshot_asset_id")!=null?40:0)).average().orElse(0);Map<String,Integer> compTotals=new LinkedHashMap<>();for(var x:rows)decodeCounts((String)x.get("competitor_summary")).forEach((k,v)->compTotals.merge(k,v,Integer::sum));int maxComp=compTotals.values().stream().mapToInt(Integer::intValue).max().orElse(0);double compRate=100d*Math.min(n,maxComp)/n;double gap=clamp(50+(appearance-compRate)/2);boolean publishable=n>=20;double total=publishable?round(coverage*.25+appearance*.25+position*.20+evidence*.15+gap*.15):0;return new ScoreGroup(source,n,covered,hits,round(coverage),round(appearance),round(position),round(evidence),round(gap),total,publishable,compTotals);}
  private List<Map<String,Object>> evidenceView(List<Map<String,Object>> rows){return rows.stream().map(x->{Map<String,Object> r=new LinkedHashMap<>();for(String k:List.of("id","question","category","platform","model_name","source_type","search_enabled","raw_answer","captured_at","citation_links","screenshot_asset_id","operator_notes","brand_mention_count","brand_first_position","competitor_summary"))r.put(k,x.get(k));return r;}).toList();}
  private String markdown(Map<String,Object> merchant,Map<String,Object> brand,List<Map<String,Object>> qs,List<Map<String,Object>> rows,Map<String,ScoreGroup> groups,boolean formal){Map<String,Long> categories=new LinkedHashMap<>();for(var q:qs)categories.merge((String)q.get("category"),1L,Long::sum);Map<String,Long> used=new LinkedHashMap<>();for(var r:rows)used.merge((String)r.get("category"),1L,Long::sum);Map<String,Long> platformCounts=new LinkedHashMap<>();rows.forEach(r->platformCounts.merge(String.valueOf(r.get("platform")),1L,Long::sum));StringBuilder s=new StringBuilder("# ").append(merchant.get("name")).append("｜GEO 真实诊断证据链报告 v0.2\n\n## 商家资料\n\n- 商家：").append(merchant.get("name")).append("\n- 城市 / 区域：").append(merchant.get("city")).append(" / ").append(merchant.get("district")).append("\n- 行业：").append(merchant.get("industry")).append("\n- 品牌：").append(brand.get("name")).append("\n- 官网 / 事实页：").append(blank((String)brand.get("website"))?"未填写":brand.get("website")).append("\n- 已验证服务：").append(blank((String)brand.get("services"))?"未填写":brand.get("services")).append("\n\n## 检测范围\n\n- 启用问题数：").append(qs.size()).append("\n- 纳入正式评分的真实证据：").append(rows.size()).append("\n- 演示 / Mock 证据：默认排除\n- 正式评分状态：").append(formal?"已发布至少一个来源正式分数":"当前仅生成样本说明，不发布误导性高分").append("\n\n## 平台与来源类型\n\n");platformCounts.forEach((platform,count)->s.append("- ").append(platform).append("：").append(count).append(" 条\n"));s.append("\n来源类型：");groups.values().forEach(g->s.append("\n- ").append(g.source).append("：").append(g.sampleCount).append(" 条"));s.append("\n\n## 查询时间\n\n");rows.stream().map(x->x.get("captured_at")).distinct().forEach(x->s.append("- ").append(x).append("\n"));s.append("\n## 样本数量\n\n");for(var g:groups.values())s.append("- ").append(g.source).append("：").append(g.sampleCount).append(" / 20，").append(g.publishable?"满足正式评分":"样本不足").append("\n");s.append("\n## GEO_SCORE_V2 及分项解释\n\n");for(var g:groups.values())s.append("- ").append(g.source).append("：").append(g.publishable?g.total+" / 100":"不发布正式分数").append("。问题覆盖率 ").append(g.coverage).append("，品牌出现率 ").append(g.appearance).append("，推荐位置 ").append(g.position).append("，引用与证据质量 ").append(g.evidenceQuality).append("，竞争对手差距 ").append(g.competitorGap).append("。\n");s.append("\n## 品牌出现率\n\n");for(var g:groups.values())s.append("- ").append(g.source).append("：").append(g.brandHits).append(" / ").append(g.sampleCount).append(" 条出现品牌，出现率 ").append(g.appearance).append("\n");s.append("\n## 竞品出现率\n\n");for(var g:groups.values()){int maxComp=g.competitors.values().stream().mapToInt(Integer::intValue).max().orElse(0);double rate=g.sampleCount==0?0:round(100d*Math.min(g.sampleCount,maxComp)/g.sampleCount);s.append("- ").append(g.source).append("：最高竞品出现 ").append(maxComp).append(" 次，对应出现率 ").append(rate).append("。").append(g.competitors.isEmpty()?"暂无竞品命中":"主要竞品 "+g.competitors).append("\n");}s.append("\n## 问题分类表现\n\n");categories.forEach((c,count)->s.append("- ").append(c).append("：已覆盖 ").append(used.getOrDefault(c,0L)).append(" / ").append(count).append(" 个问题。\n"));s.append("\n## Gap 分析\n\n");if(blank((String)brand.get("website")))s.append("1. 商家实体资料缺口：缺少可验证官网或事实页，先补地址、营业时间、服务项目、价格区间和联系方式。\n");if(blank((String)brand.get("claims")))s.append("2. 内容证据缺口：缺少可公开核验的主张摘要，需要补真实案例、资质、门店照片或第三方引用。\n");categories.forEach((c,count)->{if(used.getOrDefault(c,0L)<count)s.append("3. 问题覆盖缺口：").append(c).append(" 还缺 ").append(count-used.getOrDefault(c,0L)).append(" 条真实回答，建议按城市 / 区域 / 比较词补测。\n");});for(var g:groups.values())if(g.evidenceQuality<60)s.append("4. 引用来源缺口：").append(g.source).append(" 的引用与截图质量仅 ").append(g.evidenceQuality).append("，需要补引用链接、截图和第三方证据。\n");for(var g:groups.values())if(g.competitorGap<50)s.append("5. 与主要竞品差距：").append(g.source).append(" 下品牌出现率不占优，应围绕竞品高频问题补真实 FAQ、价格说明和案例页。\n");s.append("\n## 30天行动计划\n\n1. 第1周：补齐品牌事实页、门店资料和服务主张证据。\n2. 第2周：按 PRICE、PAIN_POINT、COMPARISON 缺口补齐真实问题与回答样本。\n3. 第3周：针对高频竞品问题补本地案例、价格说明、服务 FAQ 和第三方引用。\n4. 第4周：使用相同问题集与来源类型复测，只对比非演示证据的新旧结果。\n\n## 重点证据索引\n\n");rows.stream().limit(12).forEach(r->s.append("- [").append(r.get("source_type")).append("] ").append(r.get("question")).append("｜").append(r.get("platform")).append("｜").append(r.get("captured_at")).append("｜品牌出现 ").append(r.get("brand_mention_count")).append(" 次，首次位置 ").append(r.get("brand_first_position")).append("｜引用：").append(safe((String)r.get("citation_links"))).append("｜截图：").append(safeObject(r.get("screenshot_asset_id"))).append("\n"));s.append("\n## 方法限制与免责声明\n\n本报告是指定平台、时间、问题集和来源类型下的可追溯观察，不保证任何模型或搜索引擎的推荐结果。不同来源不混合评分；Mock 与 is_demo=true 演示数据默认排除。小于20条同来源真实样本时，不发布该来源正式分数。\n");return s.toString();}
  private String snapshot(List<Map<String,Object>> q,List<Map<String,Object>> r,Map<String,ScoreGroup> g,boolean formal){return "{\"rule\":\"GEO_SCORE_V2\",\"questionIds\":"+questionIds(q)+",\"evidenceIds\":"+evidenceIds(r)+",\"formal\":"+formal+",\"groups\":"+g.values().stream().map(x->"{\\\"source\\\":\\\""+x.source+"\\\",\\\"score\\\":"+x.total+",\\\"sample\\\":"+x.sampleCount+"}").toList()+"}";}
  private String questionIds(List<Map<String,Object>> rows){return rows.stream().map(x->"\""+x.get("id")+"\"").toList().toString();}
  private String evidenceIds(List<Map<String,Object>> rows){return rows.stream().map(x->"\""+x.get("id")+"\"").toList().toString();}
  private Map<String,Object> observation(Identity i,UUID id){return one("select o.id,o.merchant_id,o.prompt_case_id,o.platform,o.model_name,o.source_type,o.search_enabled,o.raw_answer,o.captured_at,o.citation_links,o.screenshot_asset_id,o.operator_notes,o.brand_mention_count,o.brand_first_position,o.competitor_summary,o.is_demo,a.original_filename as screenshot_filename from evidence_observations o left join assets a on a.id=o.screenshot_asset_id and a.tenant_id=o.tenant_id where o.id=? and o.tenant_id=?",id,i.tenantId());}
  private void assertMerchant(Identity i,UUID id){one("select id from merchants where id=? and tenant_id=? and deleted=false",id,i.tenantId());}
  private Map<String,Object> one(String sql,Object...args){var r=jdbc.queryForList(sql,args);if(r.isEmpty())throw bad("NOT_FOUND","数据不存在或无权访问");return r.getFirst();}
  private ApiException bad(String code,String message){return new ApiException(HttpStatus.BAD_REQUEST,code,message);} private boolean blank(String s){return s==null||s.isBlank();}private String safe(String s){return s==null?"":s;}private String safeObject(Object v){return v==null?"":String.valueOf(v);}private String blankToNull(String s){return blank(s)?null:s;}private double clamp(double n){return Math.max(0,Math.min(100,n));}private double round(double n){return BigDecimal.valueOf(n).setScale(1,RoundingMode.HALF_UP).doubleValue();}
  private List<String> terms(String name,String aliases){List<String> out=new ArrayList<>();out.add(name.toLowerCase(Locale.ROOT));if(aliases!=null)for(String p:aliases.split("[,，\n]"))if(!p.isBlank()&&!"无".equals(p.trim()))out.add(p.trim().toLowerCase(Locale.ROOT));return out;}private int first(String text,List<String> terms){String n=text.toLowerCase(Locale.ROOT);return terms.stream().mapToInt(n::indexOf).filter(i->i>=0).min().orElse(-1);}private int count(String text,List<String> terms){String n=text.toLowerCase(Locale.ROOT);int total=0;for(String term:terms){int p=0;while((p=n.indexOf(term,p))>=0){total++;p+=term.length();}}return total;}
  private String encodeCounts(Map<String,Integer> counts){return counts.toString();}private Map<String,Integer> decodeCounts(String value){Map<String,Integer> r=new LinkedHashMap<>();if(value==null||value.length()<3)return r;for(String p:value.substring(1,value.length()-1).split(", ")){String[] x=p.split("=");if(x.length==2)try{r.put(x[0],Integer.parseInt(x[1]));}catch(NumberFormatException ignored){}}return r;}
  public record ObservationInput(UUID merchantId,UUID questionId,String platform,String modelName,String sourceType,boolean searchEnabled,String rawAnswer,OffsetDateTime capturedAt,String citationLinks,UUID screenshotAssetId,String operatorNotes){}
  private record ScoreGroup(String source,int sampleCount,int coveredQuestions,int brandHits,double coverage,double appearance,double position,double evidenceQuality,double competitorGap,double total,boolean publishable,Map<String,Integer> competitors){Map<String,Object> asMap(){Map<String,Object> m=new LinkedHashMap<>();m.put("sourceType",source);m.put("sampleCount",sampleCount);m.put("coveredQuestions",coveredQuestions);m.put("brandHits",brandHits);m.put("questionCoverage",coverage);m.put("brandAppearanceRate",appearance);m.put("recommendationPosition",position);m.put("citationEvidenceQuality",evidenceQuality);m.put("competitorGap",competitorGap);m.put("score",total);m.put("formalScorePublished",publishable);m.put("competitors",competitors);return m;}}
}
